@import '../../utils/control-inactive.css';

.field {
  display: flex;
  flex-direction: column;
  gap: var(--dimension-space-050);
  width: 100%;
}

.label-row {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: var(--dimension-space-050);
}

/* ── Track ───────────────────────────────────────────────────────────────── */

.track {
  position: relative;
  width: 100%;
  height: var(--dimension-size-400);
  padding: 0 var(--dimension-space-025);
  border-radius: var(--dimension-radius-075);
  cursor: pointer;
  user-select: none;
  box-sizing: border-box;
}

.track-inner {
  position: absolute;
  inset: 0;
  border-radius: inherit;
  background-color: var(--color-background-primary);
  box-shadow: var(--effect-elevation-depressed-sm);
  pointer-events: none;
  z-index: 1;
}

/* ── Fill ────────────────────────────────────────────────────────────────── */

.fill-track {
  position: absolute;
  top: var(--dimension-space-025);
  right: 0;
  bottom: var(--dimension-space-025);
  left: 0;
  z-index: 1;
  pointer-events: none;
}

.fill {
  position: absolute;
  left: var(--dimension-space-025);
  top: 0;
  bottom: 0;
  width: max(0px, calc((var(--slider-pct, 0) / 100) * (100% - var(--dimension-size-150)) - var(--dimension-space-025)));
  background-color: var(--color-background-bold-brand);
  box-shadow: var(--effect-elevation-elevated-sm);
  border-radius: var(--dimension-radius-050);
  transition: opacity var(--effect-motion-short-2);
  pointer-events: none;
}

.track--at-min .fill {
  opacity: 0;
}

/* ── Thumb ───────────────────────────────────────────────────────────────── */

.thumb {
  position: absolute;
  top: 0;
  bottom: 0;
  left: calc((var(--slider-pct, 0) / 100) * (100% - var(--dimension-size-150)));
  width: var(--dimension-size-150);
  padding: var(--dimension-space-025);
  box-sizing: border-box;
  pointer-events: none;
  z-index: 2;
}

.thumb::before {
  content: '';
  position: absolute;
  inset: var(--dimension-space-025);
  background-color: var(--color-background-primary);
  box-shadow: var(--effect-elevation-elevated-sm);
  border-radius: var(--dimension-radius-050);
}

.thumb::after {
  content: '';
  position: absolute;
  inset: var(--dimension-space-025);
  background-color: transparent;
  border-radius: var(--dimension-radius-050);
  transition: background-color var(--effect-motion-short-2);
}

.track:hover:not(.ds-control-inactive) .thumb::after {
  background-color: var(--color-interaction-hover);
}

.track:active:not(.ds-control-inactive) .thumb::after {
  background-color: var(--color-interaction-pressed);
}

/* ── Native range input (invisible overlay) ──────────────────────────────── */

.range-input {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  margin: 0;
  padding: 0;
  opacity: 0;
  cursor: pointer;
  -webkit-appearance: none;
  appearance: none;
  outline: none;
  z-index: 3;
}

.range-input:disabled {
  cursor: not-allowed;
}

.range-input:hover {
  cursor: grab;
}

.range-input:active {
  cursor: grabbing;
}

/* Inactive: `.ds-control-inactive` (25% opacity) on `.track`. */

.track:focus-within .track-inner {
  box-shadow: var(--effect-elevation-depressed-sm), inset 0 0 0 1.25px var(--color-interaction-focus);
}

import { Component, Prop, Event, EventEmitter, h, Host } from '@stencil/core';

let idCounter = 0;

@Component({
  tag: 'ds-slider',
  styleUrl: 'Slider.css',
  scoped: true,
})
export class Slider {
  private generatedId = `ds-slider-${++idCounter}`;

  @Prop() value: number = 0;
  @Prop() min: number = 0;
  @Prop() max: number = 100;
  @Prop() step: number = 1;
  @Prop() label!: string;
  @Prop() isInactive: boolean = false;
  @Prop() valueText: string | undefined;
  /** Associates with an external <label>. Defaults to an auto-generated ID. */
  @Prop() inputId: string | undefined;

  @Event() dsChange!: EventEmitter<number>;

  private handleInput = (e: Event) => {
    this.dsChange.emit(Number((e.target as HTMLInputElement).value));
  };

  private get pct() {
    const range = this.max - this.min;
    return range === 0 ? 0 : Math.round(((this.value - this.min) / range) * 100);
  }

  render() {
    const finalId = this.inputId ?? this.generatedId;
    const pct = this.pct;

    return (
      <Host class="field">
        <div class="label-row">
          <ds-text as="label" variant="text-body-small" emphasis for={finalId}>
            {this.label}
          </ds-text>
          <ds-text as="span" variant="text-body-small" emphasis>
            {this.value}
          </ds-text>
        </div>
        <div
          class={{
            track: true,
            'ds-control-inactive': this.isInactive,
            'track--at-min': pct === 0,
          }}
          style={{ '--slider-pct': String(pct) } as Record<string, string>}
        >
          <div class="track-inner">
            <div class="fill-track"><div class="fill" /></div>
            <div class="thumb" />
          </div>
          <input
            type="range"
            id={finalId}
            min={this.min}
            max={this.max}
            step={this.step}
            value={this.value}
            disabled={this.isInactive}
            class="range-input"
            aria-valuetext={this.valueText}
            onInput={this.handleInput}
          />
        </div>
      </Host>
    );
  }
}
